public enum Symbol { X, O, EMPTY }

public class Board {
    private Symbol[][] grid;
    private int size;
    public Board(int size) {
        this.size = size;
        grid = new Symbol[size][size];
    }
    public boolean makeMove(int r, int c, Symbol s) {
        if (grid[r][c] != Symbol.EMPTY) return false;
        grid[r][c] = s;
        return true;
    }
}

