languages.python:
from enum import Enum

class Symbol(Enum):
    X = 1
    O = 2
    EMPTY = 3

class Board:
    def __init__(self, size: int):
        self.size = size
        self.grid = [[Symbol.EMPTY] * size for _ in range(size)]

    def make_move(self, r: int, c: int, s: Symbol) -> bool:
        if self.grid[r][c] != Symbol.EMPTY:
            return False
        self.grid[r][c] = s
        return True

